module.render:
const color = args.color || 'var(--accent-color)';
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const highlight = parseInt(args.highlight, 10) || 0;
const badge = args.badge ? esc(String(args.badge).trim()) : '';
const radius = args.radius && String(args.radius).trim();
const gap = args.gap && String(args.gap).trim();
const tiers = sections.map((s) => (s || '').trim()).filter(Boolean);
let cvars = `--pr-color:${color};`;
if (radius) cvars += `--pr-radius:${radius};`;
if (gap) cvars += `gap:${gap};`;
let html = `\n\n<div class="mdp-mod-pricing" style="${cvars}">`;
tiers.forEach((tt, idx) => {
  const lines = tt.split('\n');
  const name = (lines.shift() || '').replace(/^#+\s*/, '').trim();
  const price = (lines.shift() || '').trim();
  const feats = lines.join('\n').trim();
  const on = (idx + 1) === highlight;
  html += `<div class="mdp-pr-tier${on ? ' is-featured' : ''}">` +
    (on && badge ? `<div class="mdp-pr-badge">${badge}</div>` : '') +
    `<div class="mdp-pr-name">${esc(name)}</div>` +
    `<div class="mdp-pr-price">\n\n${price}\n\n</div>` +
    `<div class="mdp-pr-feats">\n\n${feats}\n\n</div></div>`;
});
html += `</div>\n\n`;
return html;
